    private DocumentBuilder createSecureDocumentBuilder() throws ParserConfigurationException {
        DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
        
        // Prevent XXE attacks
        dbf.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        dbf.setFeature("http://xml.org/sax/features/external-general-entities", false);
        dbf.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        dbf.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
        
        // Prevent entity expansion attacks
        dbf.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        dbf.setXIncludeAware(false);
        dbf.setExpandEntityReferences(false);
        
        // Set entity expansion limit
        dbf.setAttribute("http://www.oracle.com/xml/jaxp/properties/entityExpansionLimit", String.valueOf(MAX_ENTITY_EXPANSION));
        dbf.setAttribute("http://apache.org/xml/features/validation/schema/element-default", "false");
        
        dbf.setNamespaceAware(true);
        
        return dbf.newDocumentBuilder();
    }
    
    @Override
    public SOAPMessage invoke(SOAPMessage request) {
        try {
            // Validate message size
            ByteArrayOutputStream baos = new ByteArrayOutputStream();
            request.writeTo(baos);
            if (baos.size() > MAX_XML_SIZE) {
                return createErrorResponse("XML payload exceeds maximum allowed size");
            }
            
            // Extract SOAP body
            SOAPBody soapBody = request.getSOAPBody();
            
            // Parse and validate XML structure
            Document document = extractAndParseDocument(soapBody);
            
            if (document == null) {
                return createErrorResponse("Invalid XML structure");
            }
            
            // Validate XML structure depth and complexity
            if (!validateXMLStructure(document.getDocumentElement())) {
                return createErrorResponse("XML structure exceeds complexity limits");
            }
            
            // Process the XML document
            DataImportResult result = processXMLDocument(document);
            
            // Create response
            return createSuccessResponse(result);
            
        } catch (SOAPException e) {
            LOGGER.severe("SOAP processing error: " + e.getMessage());
            return createErrorResponse("SOAP processing error: " + e.getMessage());
        } catch (IOException e) {
            LOGGER.severe("I/O error: " + e.getMessage());
            return createErrorResponse("I/O error: " + e.getMessage());
        } catch (Exception e) {
            LOGGER.severe("Unexpected error: " + e.getMessage());
            return createErrorResponse("Processing error: " + e.getMessage());
        }
    }
    
    private Document extractAndParseDocument(SOAPBody soapBody) {
        try {
            NodeList children = soapBody.getChildNodes();
            for (int i = 0; i < children.getLength(); i++) {
                Node node = children.item(i);
                if (node.getNodeType() == Node.ELEMENT_NODE) {
                    // Convert SOAP element to Document
                    return convertNodeToDocument(node);
                }
            }
        } catch (Exception e) {
            LOGGER.severe("Error extracting document: " + e.getMessage());
        }
        return null;
    }
    
    private Document convertNodeToDocument(Node node) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);
        
        // Apply security features
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        factory.setExpandEntityReferences(false);
        
        DocumentBuilder builder = factory.newDocumentBuilder();
        Document newDoc = builder.newDocument();
        Node importedNode = newDoc.importNode(node, true);
        newDoc.appendChild(importedNode);
        
        return newDoc;
    }
    
    private boolean validateXMLStructure(Element root) {
        return validateDepth(root, 0) && validateComplexity(root);
    }
    
    private boolean validateDepth(Node node, int currentDepth) {
        if (currentDepth > MAX_ELEMENT_DEPTH) {
            return false;
        }
        
        NodeList children = node.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                if (!validateDepth(child, currentDepth + 1)) {
                    return false;
                }
            }
        }
        return true;
    }
    
    private boolean validateComplexity(Element root) {
        int totalAttributes = countAttributes(root);
        int totalElements = countElements(root);
        
        return totalAttributes <= MAX_ATTRIBUTES && totalElements <= MAX_CHILD_NODES;
    }
    
    private int countAttributes(Node node) {
        int count = 0;
        if (node.hasAttributes()) {
            count += node.getAttributes().getLength();
        }
        
        NodeList children = node.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                count += countAttributes(child);
            }
        }
        return count;
    }
    
    private int countElements(Node node) {
        int count = 1;
        NodeList children = node.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                count += countElements(child);
            }
        }
        return count;
    }
    
    private DataImportResult processXMLDocument(Document document) {
        DataImportResult result = new DataImportResult();
        Element root = document.getDocumentElement();
        
        String operationType = root.getAttribute("operation");
        if (operationType == null || operationType.isEmpty()) {
            operationType = "import";
        }
        
        result.setOperationType(operationType);
        
        // Process based on root element name
        String rootName = root.getNodeName();
        
        switch (rootName) {
            case "DataImport":
            case "dataImport":
                processDataImport(root, result);
                break;
            case "BulkImport":
            case "bulkImport":
                processBulkImport(root, result);
                break;
            case "EntityImport":
            case "entityImport":
                processEntityImport(root, result);
                break;
            default:
                processGenericImport(root, result);
                break;
        }
        
        return result;
    }
    
    private void processDataImport(Element root, DataImportResult result) {
        NodeList entities = root.getElementsByTagName("Entity");
        if (entities.getLength() == 0) {
            entities = root.getElementsByTagName("entity");
        }
        
        List<ImportedEntity> importedEntities = new ArrayList<>();
        
        for (int i = 0; i < entities.getLength(); i++) {
            Element entity = (Element) entities.item(i);
            ImportedEntity importedEntity = processEntity(entity);
            importedEntities.add(importedEntity);
        }
        
        result.setImportedEntities(importedEntities);
        result.setTotalRecords(importedEntities.size());
        result.setSuccessfulRecords(importedEntities.size());
        result.setStatus("SUCCESS");
    }
    
    private void processBulkImport(Element root, DataImportResult result) {
        NodeList batches = root.getElementsByTagName("Batch");
        if (batches.getLength() == 0) {
            batches = root.getElementsByTagName("batch");
        }
        
        List<ImportedEntity> allEntities = new ArrayList<>();
        
        for (int i = 0; i < batches.getLength(); i++) {
            Element batch = (Element) batches.item(i);
            NodeList records = batch.getElementsByTagName("Record");
            if (records.getLength() == 0) {
                records = batch.getElementsByTagName("record");
            }
            
            for (int j = 0; j < records.getLength(); j++) {
                Element record = (Element) records.item(j);
                ImportedEntity entity = processRecord(record);
                allEntities.add(entity);
            }
        }
        
        result.setImportedEntities(allEntities);
        result.setTotalRecords(allEntities.size());
        result.setSuccessfulRecords(allEntities.size());
        result.setStatus("SUCCESS");
    }
    
    private void processEntityImport(Element root, DataImportResult result) {
        List<ImportedEntity> entities = new ArrayList<>();
        
        NodeList children = root.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                Element element = (Element) child;
                ImportedEntity entity = processComplexEntity(element);
                entities.add(entity);
            }
        }
        
        result.setImportedEntities(entities);
        result.setTotalRecords(entities.size());
        result.setSuccessfulRecords(entities.size());
        result.setStatus("SUCCESS");
    }
    
    private void processGenericImport(Element root, DataImportResult result) {
        List<ImportedEntity> entities = new ArrayList<>();
        ImportedEntity entity = processComplexEntity(root);
        entities.add(entity);
        
        result.setImportedEntities(entities);
        result.setTotalRecords(1);
        result.setSuccessfulRecords(1);
        result.setStatus("SUCCESS");
    }
    
    private ImportedEntity processEntity(Element entity) {
        ImportedEntity imported = new ImportedEntity();
        
        String id = entity.getAttribute("id");
        String type = entity.getAttribute("type");
        
        imported.setId(id);
        imported.setType(type);
        
        Map<String, Object> data = new HashMap<>();
        NodeList children = entity.getChildNodes();
        
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                Element childElement = (Element) child;
                String key = childElement.getNodeName();
                Object value = extractValue(childElement);
                data.put(key, value);
            }
        }
        
        imported.setData(data);
        return imported;
    }
    
    private ImportedEntity processRecord(Element record) {
        ImportedEntity imported = new ImportedEntity();
        
        String id = record.getAttribute("id");
        imported.setId(id);
        imported.setType("Record");
        
        Map<String, Object> data = new HashMap<>();
        NodeList fields = record.getElementsByTagName("Field");
        if (fields.getLength() == 0) {
            fields = record.getElementsByTagName("field");
        }
        
        for (int i = 0; i < fields.getLength(); i++) {
            Element field = (Element) fields.item(i);
            String name = field.getAttribute("name");
            String value = field.getTextContent();
            data.put(name, value);
        }
        
        imported.setData(data);
        return imported;
    }
    
    private ImportedEntity processComplexEntity(Element element) {
        ImportedEntity imported = new ImportedEntity();
        
        String id = element.getAttribute("id");
        String type = element.getNodeName();
        
        imported.setId(id);
        imported.setType(type);
        
        Map<String, Object> data = extractComplexData(element);
        imported.setData(data);
        
        return imported;
    }
    
    private Map<String, Object> extractComplexData(Element element) {
        Map<String, Object> data = new HashMap<>();
        
        // Extract attributes
        if (element.hasAttributes()) {
            for (int i = 0; i < element.getAttributes().getLength(); i++) {
                Node attr = element.getAttributes().item(i);
                data.put("@" + attr.getNodeName(), attr.getNodeValue());
            }
        }
        
        // Extract child elements
        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                Element childElement = (Element) child;
                String key = childElement.getNodeName();
                Object value = extractValue(childElement);
                
                // Handle multiple elements with same name
                if (data.containsKey(key)) {
                    Object existing = data.get(key);
                    if (existing instanceof List) {
                        ((List<Object>) existing).add(value);
                    } else {
                        List<Object> list = new ArrayList<>();
                        list.add(existing);
                        list.add(value);
                        data.put(key, list);
                    }
                } else {
                    data.put(key, value);
                }
            } else if (child.getNodeType() == Node.TEXT_NODE) {
                String text = child.getTextContent().trim();
                if (!text.isEmpty()) {
                    data.put("_text", text);
                }
            }
        }
        
        return data;
    }
    
    private Object extractValue(Element element) {
        NodeList children = element.getChildNodes();
        boolean hasElementChildren = false;
        
        for (int i = 0; i < children.getLength(); i++) {
            if (children.item(i).getNodeType() == Node.ELEMENT_NODE) {
                hasElementChildren = true;
                break;
            }
        }
        
        if (hasElementChildren) {
            return extractComplexData(element);
        } else {
            return element.getTextContent().trim();
        }
    }
    
    private SOAPMessage createSuccessResponse(DataImportResult result) {
        try {
            MessageFactory messageFactory = MessageFactory.newInstance();
            SOAPMessage soapMessage = messageFactory.createMessage();
            SOAPBody soapBody = soapMessage.getSOAPBody();
            
            SOAPElement responseElement = soapBody.addChildElement("DataImportResponse", "ns", "http://enterprise.integration.platform");
            
            SOAPElement statusElement = responseElement.addChildElement("Status");
            statusElement.addTextNode(result.getStatus());
            
            SOAPElement totalElement = responseElement.addChildElement("TotalRecords");
            totalElement.addTextNode(String.valueOf(result.getTotalRecords()));
            
            SOAPElement successElement = responseElement.addChildElement("SuccessfulRecords");
            successElement.addTextNode(String.valueOf(result.getSuccessfulRecords()));
            
            SOAPElement operationElement = responseElement.addChildElement("OperationType");
            operationElement.addTextNode(result.getOperationType());
            
            SOAPElement timestampElement = responseElement.addChildElement("Timestamp");
            timestampElement.addTextNode(new Date().toString());
            
            if (result.getImportedEntities() != null && !result.getImportedEntities().isEmpty()) {
                SOAPElement entitiesElement = responseElement.addChildElement("ImportedEntities");
                
                for (ImportedEntity entity : result.getImportedEntities()) {
                    SOAPElement entityElement = entitiesElement.addChildElement("Entity");
                    
                    if (entity.getId() != null) {
                        entityElement.setAttribute("id", entity.getId());
                    }
                    if (entity.getType() != null) {
                        entityElement.setAttribute("type", entity.getType());
                    }
                    
                    SOAPElement dataElement = entityElement.addChildElement("Data");
                    dataElement.addTextNode(entity.getData().toString());
                }
            }
            
            soapMessage.saveChanges();
            return soapMessage;
            
        } catch (SOAPException e) {
            LOGGER.severe("Error creating success response: " + e.getMessage());
            return createErrorResponse("Error creating response");
        }
    }
    
    private SOAPMessage createErrorResponse(String errorMessage) {
        try {
            MessageFactory messageFactory = MessageFactory.newInstance();
            SOAPMessage soapMessage = messageFactory.createMessage();
            SOAPBody soapBody = soapMessage.getSOAPBody();
            
            SOAPFault fault = soapBody.addFault();
            fault.setFaultString(errorMessage);
            fault.setFaultCode("Server");
            
            soapMessage.saveChanges();
            return soapMessage;
            
        } catch (SOAPException e) {
            LOGGER.severe("Error creating error response: " + e.getMessage());
            return null;
        }
    }
